// ── observation-framework ──────────────────────────────────

function generateObservationFramework() {
  const data = readYaml('observation-framework.yaml') as {
    observationModes: Array<{
      modeId: string;
      displayName: string;
      description: string;
      duration: string;
      format: string;
      frequency: string;
      guidancePrompt: string;
      tips?: string[];
    }>;
    frameworkMapping: {
      layers: Array<{
        ageRange: { startMonths: number; endMonths: number };
        primaryFramework: string;
        dimensions: string[];
      }>;
    };
    dimensions: Array<Record<string, unknown>>;
  };

  const modeIds = data.observationModes.map((m) => m.modeId);
  const rawDims = data.dimensions ?? [];
  const dimIds = rawDims.map((d) => d.dimensionId as string);
  // Project dimension data: YAML uses ageRelevance + indicators, interface normalizes to ageRange + observableSignals
  const cleanDims = rawDims.map((d) => ({
    dimensionId: d.dimensionId as string,
    displayName: d.displayName as string,
    description: (d.description as string) ?? '',
    ageRange: (d.ageRelevance as { startMonths: number; endMonths: number }) ?? { startMonths: 0, endMonths: -1 },
    parentQuestion: (d.parentQuestion as string) ?? '',
    observableSignals: Array.isArray(d.indicators) ? (d.indicators as Array<{ signal: string }>).map((i) => i.signal) : [],
    guidedQuestions: (d.guidedQuestions as string[]) ?? [],
    quickTags: (d.quickTags as string[]) ?? [],
    source: (d.source as string) ?? '',
  }));

  const ts = `
export type ObservationModeId = ${modeIds.map((m) => `'${m}'`).join(' | ')};

export interface ObservationMode {
  modeId: ObservationModeId;
  displayName: string;
  description: string;
  duration: string;
  format: string;
  frequency: string;
  guidancePrompt: string | null;
  tips?: string[];
  notes?: string[];
}

export interface ObservationDimension {
  dimensionId: string;
  displayName: string;
  description: string;
  ageRange: { startMonths: number; endMonths: number };
  parentQuestion: string;
  observableSignals: string[];
  guidedQuestions: string[];
  quickTags: string[];
  source: string;
}

export interface FrameworkLayer {
  ageRange: { startMonths: number; endMonths: number };
  primaryFramework: string;
  dimensions: string[];
}

export const OBSERVATION_MODES: readonly ObservationMode[] = ${JSON.stringify(data.observationModes, null, 2)} ;

export const OBSERVATION_DIMENSIONS: readonly ObservationDimension[] = ${JSON.stringify(cleanDims, null, 2)} ;

export const FRAMEWORK_LAYERS: readonly FrameworkLayer[] = ${JSON.stringify(data.frameworkMapping?.layers ?? [], null, 2)} ;

export const DIMENSION_IDS = ${JSON.stringify(dimIds)} ;
`;

  writeGen('observation-framework.gen.ts', ts);
}

// ── growth-standards ───────────────────────────────────────

function generateGrowthStandards() {
  const data = readYaml('growth-standards.yaml') as {
    measurementTypes: Array<{
      typeId: string;
      displayName: string;
      unit: string;
      precision: number;
      ageRange: { startMonths: number; endMonths: number };
      referenceCoverage?: { startMonths: number; endMonths: number };
      frequency: string;
      standardSource: string;
      curveType: string;
    }>;
    referenceRanges?: Record<string, unknown>;
  };

  const typeIds = data.measurementTypes.map((t) => t.typeId);

  const ts = `
export type GrowthTypeId = ${typeIds.map((t) => `'${t}'`).join(' | ')};
export type CurveType = 'lms-percentile' | 'reference-range';

export interface GrowthStandard {
  typeId: GrowthTypeId;
  displayName: string;
  unit: string;
  precision: number;
  ageRange: { startMonths: number; endMonths: number };
  referenceCoverage?: { startMonths: number; endMonths: number };
  frequency: string;
  standardSource: string;
  curveType: CurveType;
}

export const GROWTH_STANDARDS: readonly GrowthStandard[] = ${JSON.stringify(data.measurementTypes, null, 2)} ;

export const GROWTH_TYPE_IDS = ${JSON.stringify(typeIds)} ;

export const REFERENCE_RANGES = ${JSON.stringify(data.referenceRanges ?? {}, null, 2)} ;
`;

  writeGen('growth-standards.gen.ts', ts);
}

// ── nurture-modes ──────────────────────────────────────────

